INSERT INTO articles (slug, title, content, image_url, badge, published_at) VALUES
  ('starfall-odyssey', 'Starfall Odyssey เปิดตัวเกม RPG แฟนตาซีอวกาศ', '<p>Starfall Odyssey เปิดตัวเกม RPG แฟนตาซีอวกาศ — รวมรายละเอียดเบื้องต้น ระบบการเล่น โหมด และกำหนดการอัปเดตสำหรับผู้เล่นไทย</p>', 'https://picsum.photos/seed/starfall-odyssey/1200/600', 'เกม', '2025-09-11 09:00:00+07'),
  ('ironclad-tactics', 'Ironclad Tactics Tactics-Lite เดือดบนพีซีและคอนโซล', '<p>Ironclad Tactics Tactics-Lite เดือดบนพีซีและคอนโซล — รวมรายละเอียดเบื้องต้น ระบบการเล่น โหมด และกำหนดการอัปเดตสำหรับผู้เล่นไทย</p>', 'https://picsum.photos/seed/ironclad-tactics/1200/600', 'พีซี', '2025-09-12 09:00:00+07'),
