-- อัปเดต home_config: hero/ticker/grid ดึงจาก DB
UPDATE home_config
SET data = jsonb_set(
            jsonb_set(
              jsonb_set(COALESCE(data,'{}'::jsonb), '{hero}',
                jsonb_build_object(
                  'img','https://picsum.photos/seed/hero/1280/640',
                  'cat','กำลังฮิต',
                  'title','หัวข้อเด่นประจำวัน'
                ), true),
              '{ticker}', to_jsonb(ARRAY[
                'เปิดตัวเกมใหม่เพียบ ต้นเดือนนี้',
                'อัปเดตใหญ่หลายเกมดัง',
                'รวมเกมอินดี้น่าเล่นสุดสัปดาห์'
              ]), true),
            '{grid}', to_jsonb(ARRAY[
                jsonb_build_object('slug','starfall-odyssey','title','Starfall Odyssey เปิดตัวเกม RPG แฟนตาซีอวกาศ','image','https://picsum.photos/seed/starfall-odyssey/800/450','badge','เกม','date','2025-10-05'),
                jsonb_build_object('slug','ironclad-tactics','title','Ironclad Tactics Tactics-Lite เดือดบนพีซีและคอนโซล','image','https://picsum.photos/seed/ironclad-tactics/800/450','badge','พีซี','date','2025-10-06'),
                jsonb_build_object('slug','kingdoms-reborn-2','title','Kingdoms Reborn II เมืองเติบโตพร้อมระบบการค้าใหม่','image','https://picsum.photos/seed/kingdoms-reborn-2/800/450','badge','เกม','date','2025-10-07'),
                jsonb_build_object('slug','mecha-frontier','title','Mecha Frontier ยิงแหลกหุ่นยักษ์แบบ Co-op 4 คน','image','https://picsum.photos/seed/mecha-frontier/800/450','badge','เกมออนไลน์','date','2025-10-08'),
                jsonb_build_object('slug','sakura-chronicles','title','Sakura Chronicles JRPG งานภาพสุดละมุน','image','https://picsum.photos/seed/sakura-chronicles/800/450','badge','คอนโซล','date','2025-10-09'),
                jsonb_build_object('slug','shadowline','title','Shadowline Tactical Shooter โหมดจัดแรงก์พร้อม!','image','https://picsum.photos/seed/shadowline/800/450','badge','พีซี','date','2025-10-10')
              ]), true
          ),
    updated_at = now()
WHERE id = 1;
